// Read module documents and split into chunks
// In production, this would read from a file system or API.
// For now, we accept documents via the ingestion API.

const inputDocs = $input.all();
const chunks = [];
const CHUNK_SIZE = 500; // characters
const CHUNK_OVERLAP = 100; // characters

for (const doc of inputDocs) {
  const content = doc.json.content || '';
  const metadata = doc.json.metadata || {};

  if (content.length <= CHUNK_SIZE) {
    chunks.push({
      content: content,
      metadata: metadata
    });
  } else {
    // Split into overlapping chunks
    let start = 0;
    let chunkIndex = 0;
    while (start < content.length) {
      const end = Math.min(start + CHUNK_SIZE, content.length);
      const chunkContent = content.substring(start, end);

      chunks.push({
        content: chunkContent,
        metadata: { ...metadata, chunk_index: chunkIndex }
      });

      start += CHUNK_SIZE - CHUNK_OVERLAP;
      chunkIndex++;
    }
  }
}

return {
  json: {
    chunks: chunks.map(c => c.content),
    metadata: chunks.map(c => c.metadata),
    total_chunks: chunks.length
  }
};

// Prepare INSERT statements for each chunk + embedding pair
const embedResponse = $('Embed Chunks').item.json.data;
const chunkData = $('Chunk Documents').item.json;

const items = [];
for (let i = 0; i < embedResponse.embeddings.length; i++) {
  items.push({
    json: {
      content: chunkData.chunks[i],
      metadata: JSON.stringify(chunkData.metadata[i]),
      embedding: JSON.stringify(embedResponse.embeddings[i])
    }
  });
}

return items;
